/**
 * SEO component that queries for data with
 * Gatsby's useStaticQuery React hook
 *
 * See: https://www.gatsbyjs.com/docs/use-static-query/
 */
import PropTypes from 'prop-types'
import React from 'react'
import { Helmet } from 'react-helmet'
import shallow from 'zustand/shallow'
import { useDependencyContext } from '@/core/context'

export interface ISeoPageDescriptionProps {
  /**
   * Page title.
   */
  title: string
  /**
   * Page description.
   */
  description?: string
  /**
   * Page language.
   */
  lang?: 'en' | string
  /**
   * HTML meta data.
   */
  meta?: Array<JSX.IntrinsicElements['meta']>
}

export function SeoPageDescription(props: ISeoPageDescriptionProps): React.ReactElement {
  const { useSiteStore } = useDependencyContext()
  const [siteTitle, siteDescription, author] = useSiteStore(
    ({ state }) => [state.title, state.description, state.author],
    shallow,
  )

  const { description = siteDescription, lang = 'en', title } = props
  const meta = [
    {
      name: 'author',
      content: author.name,
    },
    {
      name: 'description',
      content: description,
    },
    {
      property: 'og:title',
      content: title,
    },
    {
      property: 'og:description',
      content: description,
    },
    {
      property: 'og:type',
      content: 'website',
    },
    ...(props.meta ?? []),
  ]

  return (
    <Helmet
      key="seo-page-description"
      htmlAttributes={{ lang }}
      title={title}
      titleTemplate={siteTitle ? `%s | ${siteTitle}` : undefined}
      meta={meta}
    />
  )
}

SeoPageDescription.propTypes = {
  title: PropTypes.string.isRequired,
  description: PropTypes.string,
  lang: PropTypes.string,
  meta: PropTypes.arrayOf(PropTypes.object),
}
